function wireMobileAffiliateBar(){
  const bar = document.querySelector('#mobile-affiliate-bar');
  if(!bar || sessionStorage.getItem('vbt-vpn-bar-closed')) return;
  document.querySelector('#mobile-affiliate-close').onclick = () => { sessionStorage.setItem('vbt-vpn-bar-closed','1'); bar.remove(); };
  window.addEventListener('scroll',()=>{ if(window.innerWidth <= 640 && window.scrollY > 760) bar.classList.add('show'); }, { passive: true });
}
