function waLink(message){ const raw = state.config.whatsapp || ''; return raw.includes('[') ? '#' : `https://wa.me/${raw.replace(/\D/g,'')}?text=${encodeURIComponent(message)}`; }
function card(p){ return `<article class="card product-card"><div class="product-media"><span class="badge ${p.oldPrice?'offer':''}">${pc(p,'badge')}</span>${productImage(p)}</div><div class="product-body"><div class="muted">${pc(p,'category')}</div><div class="product-title">${p.name}</div><p class="muted">${pc(p,'summary')}</p><div class="price">${money(p.price)} ${p.oldPrice?`<span class="old-price">${money(p.oldPrice)}</span>`:''}</div><div class="stock ${p.available?'':'out'}">${p.available?pc(p,'stock'):tr('notAvailable')}</div><div class="product-actions"><a class="btn btn-outline" href="${basePath}/productos/${p.slug}/">${tr('details')}</a><button class="btn btn-primary" data-add="${p.slug}" ${p.available?'':'disabled'}>${tr('addCart')}</button></div></div></article>`; }
function wireAddButtons(){ document.querySelectorAll('[data-add]').forEach(btn=>btn.addEventListener('click',()=>addCart(btn.dataset.add))); }
function addCart(slug){ const item = state.cart.find(i=>i.slug===slug); item ? item.qty++ : state.cart.push({slug, qty:1}); saveCart(); openCart(); }
function saveCart(){ localStorage.setItem('vbt-cart', JSON.stringify(state.cart)); updateCartCount(); }
function updateCartCount(){ const el=document.querySelector('#cart-count'); if(el) el.textContent = state.cart.reduce((n,i)=>n+i.qty,0); }
function openCart(){ document.querySelector('#cart-drawer').classList.add('open'); renderCart(); }
function closeCart(){ document.querySelector('#cart-drawer').classList.remove('open'); }
function renderCart(){
  const lines = state.cart.map(i=>({ ...i, product: state.products.find(p=>p.slug===i.slug)})).filter(i=>i.product);
  const subtotal = lines.reduce((sum,i)=>sum+i.product.price*i.qty,0); const shipping = subtotal ? 4.99 : 0; const total=subtotal+shipping;
  document.querySelector('#cart-content').innerHTML = lines.length ? lines.map(i=>`<div class="cart-line"><div><strong>${i.product.name}</strong><div>${money(i.product.price)} · ${pc(i.product,'category')}</div><div class="qty"><button data-qty="${i.slug}" data-delta="-1">−</button><span>${i.qty}</span><button data-qty="${i.slug}" data-delta="1">+</button><button data-remove="${i.slug}">${tr('delete')}</button></div></div><strong>${money(i.product.price*i.qty)}</strong></div>`).join('') : `<p class="muted">${tr('emptyCart')}</p>`;
  document.querySelector('#cart-totals').innerHTML = `<div class="total-line"><span>${tr('subtotal')}</span><strong>${money(subtotal)}</strong></div><div class="total-line"><span>${tr('shipping')}</span><strong>${money(shipping)}</strong></div><div class="total-line"><span>${tr('total')}</span><strong>${money(total)}</strong></div>`;
  document.querySelectorAll('[data-qty]').forEach(b=>b.onclick=()=>{ const item=state.cart.find(i=>i.slug===b.dataset.qty); item.qty += Number(b.dataset.delta); if(item.qty<1) state.cart=state.cart.filter(i=>i.slug!==b.dataset.qty); saveCart(); renderCart(); });
  document.querySelectorAll('[data-remove]').forEach(b=>b.onclick=()=>{ state.cart=state.cart.filter(i=>i.slug!==b.dataset.remove); saveCart(); renderCart(); });
  document.querySelector('#cart-whatsapp').href = waLink(`${tr('orderMessage')} ${lines.map(i=>`${i.qty} x ${i.product.name} (${money(i.product.price)})`).join(', ')}. ${tr('totalEstimate')} ${money(total)}. ${tr('orderConfirm')}`);
}
function cartDrawer(){ document.querySelector('#cart-drawer').innerHTML = `<div class="drawer-backdrop" id="cart-close"></div><aside class="cart-panel"><div style="display:flex;justify-content:space-between;align-items:center;gap:12px"><h2>${tr('cart')}</h2><button class="icon-btn" id="cart-x">×</button></div><div id="cart-content"></div><div id="cart-totals"></div><div class="grid"><a id="cart-whatsapp" class="btn btn-green" href="#">${tr('sendOrder')}</a><button class="btn btn-outline" id="cart-clear">${tr('clearCart')}</button></div></aside>`; document.querySelector('#cart-close').onclick=closeCart; document.querySelector('#cart-x').onclick=closeCart; document.querySelector('#cart-clear').onclick=()=>{state.cart=[];saveCart();renderCart();}; }
function securitySupportBlock(){ return `<section class="section" id="seguridad-soporte"><div class="container"><div class="section-head"><div><h2>${tr('supportTitle')}</h2><p class="muted">${tr('supportLead')}</p></div><a class="btn btn-primary" href="${basePath}/soporte/">${tr('guides')}</a></div><div class="grid grid-3">${guideData[state.lang].slice(0,3).map(([title,steps], index)=>`<article class="card benefit"><p class="meta">${guideAuthor} · ${guideMeta[index].date}</p><h3>${title}</h3><p class="muted">${steps}</p><a class="btn btn-outline" href="${basePath}/guias/${guideMeta[index].slug}/">${tr('details')}</a></article>`).join('')}</div></div></section>`; }
