function compareBlock(){ const rows=['resolution','os','price','recommendedUse']; const labels=tr('compareLabels'); return `<section class="section"><div class="container"><h2>${tr('compareTitle')}</h2><div class="compare-wrap" style="margin-top:24px"><table><thead><tr><th>${labels.data}</th>${state.products.slice(0,4).map(p=>`<th>${p.name}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr><th>${labels[r]}</th>${state.products.slice(0,4).map(p=>`<td>${r==='price'?money(p.price):r==='recommendedUse'?pc(p,'recommendedUse'):p[r]}</td>`).join('')}</tr>`).join('')}</tbody></table></div></div></section>`; }
function stars(count){ return '★★★★★'.slice(0, count) + '☆☆☆☆☆'.slice(0, 5 - count); }
function reviewForm(){
  return `<div class="review-form-wrap" id="review-form-wrap" hidden><form class="card form review-form" id="review-form"><h3>${tr('reviewFormTitle')}</h3><label>${tr('reviewName')}<input class="input" name="name" required minlength="2" placeholder="Mariana R."></label><label>${tr('reviewOrder')}<input class="input" name="order" required placeholder="VBT-0000"></label><label>${tr('reviewProduct')}<input class="input" name="product" required></label><div class="review-form-grid"><label>${tr('reviewRating')}<select class="input" name="rating" required><option value="5">5/5</option><option value="4">4/5</option><option value="3">3/5</option><option value="2">2/5</option><option value="1">1/5</option></select></label><label>${tr('reviewCity')}<input class="input" name="city" required></label></div><label>${tr('reviewMessage')}<textarea class="input" name="message" required minlength="20"></textarea></label><button class="btn btn-primary" type="submit">${tr('reviewSubmit')}</button><p class="muted" id="review-status"></p></form><form id="review-internal-form" hidden><textarea name="pendingReviews" id="pending-reviews"></textarea></form><div class="review-toast" id="review-toast" role="status" aria-live="polite" hidden><strong>${tr('reviewSentTitle')}</strong><span>${tr('reviewStatus')}</span></div></div>`;
}
function wireReviewForm(){
  const toggle = document.querySelector('#review-toggle');
  const wrap = document.querySelector('#review-form-wrap');
  const form = document.querySelector('#review-form');
  if(!toggle || !wrap || !form) return;
  toggle.onclick = () => { wrap.hidden = !wrap.hidden; if(!wrap.hidden) form.querySelector('input').focus(); };
  form.onsubmit = e => {
    e.preventDefault();
    const data = new FormData(form);
    const entry = {
      name: data.get('name'),
      order: data.get('order'),
      product: data.get('product'),
      rating: data.get('rating'),
      city: data.get('city'),
      message: data.get('message'),
      submittedAt: new Date().toISOString(),
      status: 'pending-validation'
    };
    let stored = [];
    try { stored = JSON.parse(localStorage.getItem('vbt-pending-reviews') || '[]'); } catch(e) {}
    stored.push(entry);
    try { localStorage.setItem('vbt-pending-reviews', JSON.stringify(stored)); } catch(e) {}
    document.querySelector('#pending-reviews').value = JSON.stringify(stored);
    document.querySelector('#review-status').textContent = tr('reviewStatus');
    const toast = document.querySelector('#review-toast');
    toast.hidden = false;
    toast.classList.add('show');
    form.reset();
    setTimeout(()=>toast.classList.remove('show'), 3200);
    setTimeout(()=>{ toast.hidden = true; }, 3600);
  };
}
function reviewsFaqBlock(){ return `<section class="section alt" id="faq"><div class="container"><div class="section-head"><div><h2>${tr('reviewsTitle')}</h2><p class="muted">${tr('reviewsText')}</p></div><button class="btn btn-primary" id="review-toggle" type="button">${tr('reviewButton')}</button></div><div class="review-grid">${reviewSamples[state.lang].map(r=>`<article class="card review-card"><div class="review-top"><span class="stars" aria-label="${r.rating} de 5">${stars(r.rating)}</span></div><p>${r.text}</p><div class="review-meta"><strong>${r.name}</strong><span>${r.city} · ${r.product}</span><time>${r.date}</time></div></article>`).join('')}</div>${reviewForm()}<h2 style="margin-top:42px">${tr('faqTitle')}</h2><div class="faq" style="margin-top:22px">${faqData[state.lang].map(([q,a])=>`<details><summary>${q}</summary><p class="muted">${a}</p></details>`).join('')}</div></div></section>`; }
function renderProducts(){ document.querySelector('main').innerHTML = `<section class="section"><div class="container"><h1>${tr('allProducts')}</h1><p class="muted">${tr('currencyNote')}</p><div class="controls"><input class="input" id="q" placeholder="${tr('search')}"><select class="filter-select" id="cat"><option value="">${tr('category')}</option>${[...new Set(state.products.map(p=>pc(p,'category')))].map(c=>`<option>${c}</option>`).join('')}</select><select class="filter-select" id="price"><option value="">${tr('price')}</option><option value="0-30">0-30</option><option value="30-60">30-60</option><option value="60-999">60+</option></select><select class="filter-select" id="avail"><option value="">${tr('availability')}</option><option value="true">${tr('available')}</option><option value="false">${tr('outOfStock')}</option></select><select class="sort-select" id="sort"><option value="popular">${tr('popular')}</option><option value="low">${tr('lowPrice')}</option><option value="high">${tr('highPrice')}</option></select></div><div class="grid grid-3" id="catalog"></div></div></section>`; const render=()=>{ let list=[...state.products]; const q=document.querySelector('#q').value.toLowerCase(); const cat=document.querySelector('#cat').value; const pr=document.querySelector('#price').value; const av=document.querySelector('#avail').value; const sort=document.querySelector('#sort').value; if(q) list=list.filter(p=>p.name.toLowerCase().includes(q)); if(cat) list=list.filter(p=>pc(p,'category')===cat); if(pr){const [a,b]=pr.split('-').map(Number); list=list.filter(p=>p.price>=a&&p.price<=b);} if(av) list=list.filter(p=>String(p.available)===av); list.sort((a,b)=>sort==='low'?a.price-b.price:sort==='high'?b.price-a.price:b.popular-a.popular); document.querySelector('#catalog').innerHTML=list.map(card).join(''); wireAddButtons();}; document.querySelectorAll('.controls input,.controls select').forEach(el=>el.addEventListener('input',render)); render(); }
function renderProductDetail(){ const slug=location.pathname.split('/').filter(Boolean).pop(); const p=state.products.find(x=>x.slug===slug) || state.products[0]; const labels=tr('compareLabels'); document.title=`${p.name} | VisionBox Tech`; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><div class="breadcrumb"><a href="${basePath}/productos/">${tr('breadcrumbProducts')}</a> / ${p.name}</div><div class="product-detail"><div><div class="gallery">${productImage(p)}</div>${p.imageCredit?`<p class="image-credit">${tr('source')}: <a href="${p.imageCredit.url}" target="_blank" rel="noopener">${p.imageCredit.label}</a></p>`:''}</div><div><span class="eyebrow">${pc(p,'category')}</span><h1>${p.name}</h1><p class="lead">${pc(p,'description')}</p><div class="price">${money(p.price)} ${p.oldPrice?`<span class="old-price">${money(p.oldPrice)}</span>`:''}</div><p class="muted">${tr('currencyNote')}</p><p class="stock ${p.available?'':'out'}">${p.available?pc(p,'stock'):tr('notAvailable')}</p><div class="hero-actions"><button class="btn btn-primary" data-add="${p.slug}" ${p.available?'':'disabled'}>${tr('addCart')}</button><a class="btn btn-green" href="${waLink(`${tr('interested')} ${p.name}, ${tr('price').toLowerCase()} ${money(p.price)}. ${tr('confirmProduct')}`)}">${tr('buyWhatsApp')}</a></div><div class="detail-list">${[[labels.resolution,p.resolution],[labels.os,p.os],[labels.price,money(p.price)],[labels.recommendedUse,pc(p,'recommendedUse')]].map(([k,v])=>`<div><strong>${k}</strong><br><span class="muted">${v}</span></div>`).join('')}</div><h2>${tr('featuresTitle')}</h2><ul>${pc(p,'features').map(x=>`<li>${x}</li>`).join('')}</ul><h2>${tr('boxTitle')}</h2><ul>${pc(p,'box').map(x=>`<li>${x}</li>`).join('')}</ul><h2>${tr('compatibilityTitle')}</h2><p>${pc(p,'compatibility').join(', ')}. ${pc(p,'warranty')} ${pc(p,'shipping')}</p>${ipvanishProductCard(p)}</div></div></div></section><section class="section alt"><div class="container"><h2>${tr('tutorialsTitle')}</h2>${videoEmbed(p.tutorial)}</div></section><section class="section"><div class="container"><h2>${tr('relatedTitle')}</h2><div class="grid grid-3">${state.products.filter(x=>x.slug!==p.slug).slice(0,3).map(card).join('')}</div></div></section>`; wireAffiliateTracking(); wireIpvanishAffiliateCarousel(); wireAddButtons(); }
function renderInfo(page){ const map={how:[tr('howTitle'),`${tr('howLead')} ${tr('paymentMethod')}. WhatsApp.`],support:[tr('supportTitle'),tr('supportLead')],contact:[tr('contactTitle'),tr('contactLead')]}; const [title,txt]=map[page]; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${title}</h1><p class="lead">${txt}</p>${page==='contact'?contactForm():page==='support'?supportContent():howBlock()}</div></section>`; if(page==='contact') wireForm(); }
function supportContent(){ return `<div class="guide-grid">${guideData[state.lang].map(([title,steps,notes], index)=>`<article class="card article-card"><div class="guide-video">${videoEmbed(guideMeta[index].video)}</div><div class="article-body"><p class="meta">${guideAuthor} · ${guideMeta[index].date}</p><h2>${title}</h2><p>${steps}</p><p class="muted">${notes}</p><a class="btn btn-outline" href="${basePath}/guias/${guideMeta[index].slug}/">${tr('details')}</a></div></article>`).join('')}</div>`; }
function renderGuide(){ const slug=location.pathname.split('/').filter(Boolean).pop(); const index=guideMeta.findIndex(g=>g.slug===slug); const guide=guideData[state.lang][index >= 0 ? index : 0]; const meta=guideMeta[index >= 0 ? index : 0]; const vpnInline = slug==='privacidad-android-tv-box' || slug==='vpn-dispositivo-streaming' ? `<div class="notice">${tr('affiliateNoticeLong')}</div>${ipvanishProductCard({slug:'android-tv-box-pro',name:'Android TV Box',category:'Android TV',os:'Android TV'})}` : ''; document.title=`${guide[0]} | VisionBox Tech`; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><div class="breadcrumb"><a href="${basePath}/soporte/">${tr('supportTitle')}</a> / ${guide[0]}</div><article class="card legal-list" style="padding:28px"><p class="meta">${guideAuthor} · ${meta.date}</p><h1>${guide[0]}</h1><p class="lead">${guide[1]}</p>${vpnInline}<h2>${tr('tutorialsTitle')}</h2>${videoEmbed(meta.video)}<h2>${tr('supportTitle')}</h2><p class="muted">${guide[2]}</p></article></div></section>`; wireAffiliateTracking(); wireIpvanishAffiliateCarousel(); }
function contactForm(){ return `<form class="card form" id="contact-form" style="padding:24px;max-width:760px"><label>${tr('name')}<input class="input" name="name" required minlength="2"></label><label>${tr('email')}<input class="input" name="email" type="email" required></label><label>${tr('message')}<textarea class="input" name="message" required minlength="10"></textarea></label><a class="btn btn-outline" href="mailto:${state.config.email}">${state.config.email}</a><button class="btn btn-primary" type="submit">${tr('sendOrder')}</button><p id="form-status" class="muted"></p></form>`; }
function wireForm(){ document.querySelector('#contact-form').addEventListener('submit',e=>{e.preventDefault(); const data=new FormData(e.currentTarget); const text=`${tr('name')}: ${data.get('name')} | ${tr('email')}: ${data.get('email')} | ${tr('message')}: ${data.get('message')}`; document.querySelector('#form-status').textContent=tr('formOk'); window.open(waLink(text),'_blank','noopener');}); }
function renderLegal(){ document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${tr('legalTitle')}</h1><p class="lead">${tr('legalLead')}</p><div class="legal-list">${legalData[state.lang].map(([id,title,body])=>`<article class="card" id="${id}"><h2>${title}</h2><p class="muted">${body}</p>${id==='afiliados'?'':`<p>${tr('independent')}</p>`}</article>`).join('')}</div></div></section>`; }
function renderAbout(){ const [title, body] = aboutData[state.lang]; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${title}</h1><p class="lead">${body}</p><div class="grid grid-3" style="margin-top:28px"><article class="card benefit"><h2>${tr('navProducts')}</h2><p class="muted">${tr('footerText')}</p></article><article class="card benefit"><h2>${tr('supportTitle')}</h2><p class="muted">${tr('supportLead')}</p></article><article class="card benefit"><h2>${tr('navContact')}</h2><p class="muted">${state.config.address}<br>${state.config.email}<br>${state.config.whatsapp}</p></article></div></div></section>`; }
function render404(){ document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${tr('notFoundTitle')}</h1><p class="lead">${tr('notFoundText')}</p><a class="btn btn-primary" href="${basePath}/">${tr('backHome')}</a></div></section>`; }
async function init(){ await loadData(); document.documentElement.lang = state.lang === 'us' ? 'en' : state.lang; header(); footer(); cartDrawer(); updateCartCount(); const page=document.body.dataset.page; if(page==='home') renderHome(); if(page==='products') renderProducts(); if(page==='product') renderProductDetail(); if(page==='guide') renderGuide(); if(page==='ipvanish') renderIpvanish(); if(page==='affiliate-transparency') renderAffiliateTransparency(); if(page==='how') renderInfo('how'); if(page==='support') renderInfo('support'); if(page==='contact') renderInfo('contact'); if(page==='legal') renderLegal(); if(page==='about') renderAbout(); if(page==='404') render404(); }
init();
